var e=[{id:`L3_1`,type:`dialog`,speaker:`CITIZEN_NPC_PROSECUTOR_NULL`,text:{KOREA:`██양, 여기는 신성한 법정입니다.`,JPN:`██さん、ここは神聖なる法廷です。`,ENG:`Miss ██, you are under oath.`,TWN:`██，這裡是神聖的法庭。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CITIZEN_NPC_PROSECUTOR_NULL`,text:{KOREA:`거짓말 하지 말고 솔직하게 말하면 돼요.`,JPN:`嘘をつかず、正直に答えてください。`,ENG:`All you have to do is speak the truth.`,TWN:`不可以說謊，只要照實說就好。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_QM`,text:{KOREA:`……어른들이 그랬어요. 우리 엄마랑 아빠가 큰 잘못을 저질렀대요.`,JPN:`……大人たちが言ってました。私のママとパパが大きな過ちを犯したって。`,ENG:`...The adults told me. That my mom and dad did something very bad.`,TWN:`……大人們說，我爸爸和媽媽犯下大錯。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_QM`,text:{KOREA:`제가 솔직하게 말하면, 엄마랑 아빠는 감옥에 가나요?`,JPN:`私が正直に話したら、ママとパパは刑務所に行くことになるんですか？`,ENG:`If I tell the truth, will Mom and Dad go to prison?`,TWN:`如果我說實話，那爸爸媽媽會進監獄嗎？`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`CITIZEN_NPC_PROSECUTOR_NULL`,text:{KOREA:`그러지 않으려고 하는 거예요.`,JPN:`そうならないように、今こうしているのです。`,ENG:`We are doing this so that they don't.`,TWN:`我現在就是想幫助他們。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`CITIZEN_NPC_PROSECUTOR_NULL`,text:{KOREA:`그 날 집에서 무슨 일이 있었는지 본 사람은 ██양뿐이에요.`,JPN:`あの日、家で何があったのか。見たのは██さんだけです。`,ENG:`You are the only witness of what happened at the house that day, Miss ██.`,TWN:`那天在家裡發生的事，██是唯一的目擊者。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`CITIZEN_NPC_PROSECUTOR_NULL`,text:{KOREA:`██양의 증언이 중요합니다.`,JPN:`██さんの証言が重要なのですよ。`,ENG:`Your testimony is highly relevant to this case.`,TWN:`██的證詞很重要。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`CITIZEN_NPC_PROSECUTOR_NULL`,text:{KOREA:`자, 그 날 ██양이 본 대로 재판장님께 설명해 주세요.`,JPN:`では、あの日██さんが見たことを裁判長に説明してくれますか。`,ENG:`Now, please describe to the judge what you saw that day.`,TWN:`來，██，把你當天看到的，一五一十地跟法官說。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_QM`,text:{KOREA:`……그 날 밤에, 아빠 친구라는 아저씨가 집에 찾아왔어요.`,JPN:`……あの日の夜、パパの友だちだっていうおじさんが家に訪ねて来ました。`,ENG:`...That night, a man who called himself a "friend" of my dad's visited us.`,TWN:`……那天晚上，有一個叔叔來我們家，他說他是爸爸的朋友。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_QM`,text:{KOREA:`엄마가 방에 들어가라고 해서 전 제 방에 있었어요.`,JPN:`ママに部屋に行きなさいと言われたので、私は自分の部屋にいました。`,ENG:`Mom told me to go to my room, so I stayed there.`,TWN:`媽媽叫我進房間，所以我就待在自己的房間裡。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_QM`,text:{KOREA:`그러다가…. 거실에서 엄마가 우는 소리가 들려서….`,JPN:`それから……リビングでママが泣く声が聞こえて……`,ENG:`Then... I heard my mom crying... and...`,TWN:`突然間…從客廳傳來媽媽的哭聲…`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CITIZEN_NPC_PROSECUTOR_NULL`,text:{KOREA:`왜 울고 있었죠, ██양?`,JPN:`どうして泣いていたのですか？　██さん。`,ENG:`Why was she crying, Miss ██?`,TWN:`██，媽媽為什麼哭呢？`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_QM`,text:{KOREA:`잘…. 잘 모르겠어요. 기억 안 나요.`,JPN:`よく……よくわからないです。憶えてません。`,ENG:`I... I'm not sure. I can't remember.`,TWN:`我…我不知道，我不記得了。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CITIZEN_NPC_PROSECUTOR_NULL`,text:{KOREA:`██양, 지금 증언을 바꾸면 곤란합니다.`,JPN:`██さん、今証言を変えられては困ります。`,ENG:`Miss ██, changing your testimony now is not a good idea.`,TWN:`██，你現在改證詞會很麻煩。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`CITIZEN_NPC_PROSECUTOR_NULL`,text:{KOREA:`다시 한 번 묻죠. 왜 엄마가 울고 있었나요?`,JPN:`もう一度聞きましょう。どうしてお母さんが泣いていたのですか？`,ENG:`Let me ask again. Why was your mother crying?`,TWN:`我再問你一次，媽媽為什麼在哭呢？`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_QM`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`CITIZEN_NPC_PROSECUTOR_NULL`,text:{KOREA:`……하아.`,JPN:`……はあ。`,ENG:`...*Sigh*`,TWN:`……呼。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`CITIZEN_NPC_PROSECUTOR_NULL`,text:{KOREA:`죄송합니다, 재판장님. 다음 증인을 신청하겠습니다.`,JPN:`申し訳ありません、裁判長。次の証人を申請します。`,ENG:`I'm sorry, your honor. I would like to call the next witness to the stand.`,TWN:`抱歉，法官，我要聲請傳喚下一個證人。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}}];export{e as default};